/**
 * IndexNow — notify search engines (Bing, Yandex, Seznam, Naver)
 * about new or updated pages immediately after build.
 *
 * The URL list is read from the sitemap generated by @astrojs/sitemap
 * (dist/sitemap-0.xml), so new pages are submitted automatically —
 * no manual list to maintain.
 *
 * Usage: node scripts/ping-indexnow.mjs   (runs automatically via postbuild)
 */

import { readFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';

const SITE = 'https://hotzaa-lapoal.info';
const KEY = '5620f623b5b147d1993ca83861041bcf';
const KEY_LOCATION = `${SITE}/${KEY}.txt`;

const sitemapPath = fileURLToPath(new URL('../dist/sitemap-0.xml', import.meta.url));

let xml;
try {
  xml = await readFile(sitemapPath, 'utf8');
} catch {
  console.error(`IndexNow: sitemap not found at ${sitemapPath} — run "npm run build" first.`);
  process.exit(1);
}

const urlList = [...new Set([...xml.matchAll(/<loc>([^<]+)<\/loc>/g)].map(m => m[1].trim()))]
  .filter(url => url.startsWith(SITE));

if (urlList.length === 0) {
  console.error('IndexNow: no URLs found in sitemap — nothing to submit.');
  process.exit(1);
}

const payload = {
  host: 'hotzaa-lapoal.info',
  key: KEY,
  keyLocation: KEY_LOCATION,
  urlList,
};

async function ping(engine) {
  const endpoint = `https://${engine}/indexnow`;
  try {
    const res = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json; charset=utf-8' },
      body: JSON.stringify(payload),
    });
    console.log(`  ${engine}: ${res.status} ${res.statusText}`);
  } catch (err) {
    console.log(`  ${engine}: error — ${err.message}`);
  }
}

console.log(`IndexNow: submitting ${urlList.length} URLs from sitemap...`);
await Promise.all([
  ping('api.indexnow.org'),
  ping('www.bing.com'),
  ping('yandex.com'),
]);
console.log('Done.');
